  '{"id":"01KFPE3R065TT50977VKXE220J","title":"Sedra Solutions x New North Weekly Meeting 01.21.26","summary":null,"duration":16.639999389648438,"speakers":[],"sentences":[{"text":"Hi.","index":0,"end_time":40.09,"speaker_id":0,"start_time":39.77,"speaker_name":null},{"text":"How are you doing?","index":1,"end_time":43.21,"speaker_id":1,"start_time":42.33,"speaker_name":null},{"text":"Good.","index":2,"end_time":43.77,"speaker_id":1,"start_time":43.45,"speaker_name":null},{"text":"How are you?","index":3,"end_time":44.41,"speaker_id":1,"start_time":43.77,"speaker_name":null},{"text":"Good.","index":4,"end_time":45.77,"speaker_id":1,"start_time":45.37,"speaker_name":null},{"text":"Hi.","index":5,"end_time":47.45,"speaker_id":1,"start_time":46.97,"speaker_name":null},{"text":"Hi.","index":6,"end_time":48.81,"speaker_id":2,"start_time":48.33,"speaker_name":null},{"text":"How are you guys?","index":7,"end_time":49.61,"speaker_id":2,"start_time":48.81,"speaker_name":null},{"text":"Good.","index":8,"end_time":50.65,"speaker_id":1,"start_time":50.25,"speaker_name":null},{"text":"How about you?","index":9,"end_time":51.29,"speaker_id":1,"start_time":50.65,"speaker_name":null},{"text":"How''s your week going?","index":10,"end_time":52.09,"speaker_id":1,"start_time":51.29,"speaker_name":null},{"text":"Good.","index":11,"end_time":52.86,"speaker_id":1,"start_time":52.7,"speaker_name":null},{"text":"Good.","index":12,"end_time":53.18,"speaker_id":1,"start_time":52.86,"speaker_name":null},{"text":"Awesome.","index":13,"end_time":54.86,"speaker_id":1,"start_time":54.3,"speaker_name":null},{"text":"I''ve been thinking about Switzerland a lot and how I want to go back.","index":14,"end_time":57.26,"speaker_id":1,"start_time":54.86,"speaker_name":null},{"text":"I know, it''s so amazing.","index":15,"end_time":59.9,"speaker_id":0,"start_time":58.22,"speaker_name":null},{"text":"I don''t blame you.","index":16,"end_time":61.5,"speaker_id":2,"start_time":60.38,"speaker_name":null},{"text":"Yes.","index":17,"end_time":62.86,"speaker_id":1,"start_time":62.38,"speaker_name":null},{"text":"We''re trying to get some pictures printed like for our walls from our trip and we both are just like, when can we go back?","index":18,"end_time":68.94,"speaker_id":1,"start_time":63.02,"speaker_name":null},{"text":"Right place.","index":19,"end_time":70.62,"speaker_id":1,"start_time":69.1,"speaker_name":null},{"text":"Beautiful.","index":20,"end_time":71.86,"speaker_id":1,"start_time":71.18,"speaker_name":null},{"text":"Just ridiculous.","index":21,"end_time":72.94,"speaker_id":0,"start_time":71.86,"speaker_name":null},{"text":"I know.","index":22,"end_time":74.42,"speaker_id":1,"start_time":73.82,"speaker_name":null},{"text":"I miss it every day.","index":23,"end_time":75.66,"speaker_id":1,"start_time":74.42,"speaker_name":null},{"text":"It almost ruined me now for any other vacation.","index":24,"end_time":78.62,"speaker_id":1,"start_time":76.22,"speaker_name":null},{"text":"Like, I mean, kind of gonna be terrible.","index":25,"end_time":81.02,"speaker_id":1,"start_time":78.7,"speaker_name":null},{"text":"Nothing will compare.","index":26,"end_time":85.4,"speaker_id":2,"start_time":84.36,"speaker_name":null},{"text":"Yeah, but that''s a good problem to have.","index":27,"end_time":87.56,"speaker_id":1,"start_time":85.88,"speaker_name":null},{"text":"It''s nice to know there''s a place that you can go.","index":28,"end_time":89.48,"speaker_id":1,"start_time":87.56,"speaker_name":null},{"text":"It''s awesome like that.","index":29,"end_time":91.08,"speaker_id":1,"start_time":89.72,"speaker_name":null},{"text":"So have to go back someday.","index":30,"end_time":94.36,"speaker_id":1,"start_time":91.08,"speaker_name":null},{"text":"Definitely.","index":31,"end_time":96.36,"speaker_id":0,"start_time":95.64,"speaker_name":null},{"text":"Let me share my screen here.","index":32,"end_time":99.64,"speaker_id":1,"start_time":97.96,"speaker_name":null},{"text":"So, just wanted to start off with a couple of updates for organic social.","index":33,"end_time":103.48,"speaker_id":1,"start_time":99.72,"speaker_name":null},{"text":"We''ve seen a good uptick in followers and connections on Fahad''s page.","index":34,"end_time":108.44,"speaker_id":1,"start_time":104.12,"speaker_name":null},{"text":"The reach and engagement went down, which is just because we have run out of post.","index":35,"end_time":111.88,"speaker_id":1,"start_time":108.6,"speaker_name":null},{"text":"So Fahad, whenever you get a chance, if you could fill out this sheet that I sent.","index":36,"end_time":115.96,"speaker_id":1,"start_time":111.88,"speaker_name":null},{"text":"Because then once we can get those posts scheduled, we''ll.","index":37,"end_time":118.44,"speaker_id":1,"start_time":116.04,"speaker_name":null},{"text":"We''ll get that back up.","index":38,"end_time":119.56,"speaker_id":1,"start_time":118.44,"speaker_name":null},{"text":"But I sent that over and I can send it over in our meeting recap too.","index":39,"end_time":123.8,"speaker_id":1,"start_time":121,"speaker_name":null},{"text":"So you have it.","index":40,"end_time":124.52,"speaker_id":1,"start_time":123.8,"speaker_name":null},{"text":"Sure.","index":41,"end_time":125.4,"speaker_id":1,"start_time":125.08,"speaker_name":null},{"text":"But yeah, then we can do that.","index":42,"end_time":126.76,"speaker_id":1,"start_time":125.4,"speaker_name":null},{"text":"The company page is doing well as too.","index":43,"end_time":129.08,"speaker_id":1,"start_time":126.84,"speaker_name":null},{"text":"We have some new posts that I just got scheduled and that AI Investigator post is going to go out tomorrow, Jackie, that we had discussed with that new graphic.","index":44,"end_time":137.16,"speaker_id":1,"start_time":129.4,"speaker_name":null},{"text":"So that boost the engagement a little bit more as well on the main page.","index":45,"end_time":140.84,"speaker_id":1,"start_time":137.32,"speaker_name":null},{"text":"But we have posts scheduled out now to through the first week of February, I believe.","index":46,"end_time":145.02,"speaker_id":1,"start_time":140.84,"speaker_name":null},{"text":"But if anything new comes along, like if you''re doing any new blogs or anything like that that you think would be noteworthy for the main page, I can just throw in a couple of extra ones and just kind of add them to what we currently have scheduled out.","index":47,"end_time":157.1,"speaker_id":1,"start_time":145.58,"speaker_name":null},{"text":"Yeah.","index":48,"end_time":159.42,"speaker_id":1,"start_time":158.94,"speaker_name":null},{"text":"So we''ll continue to keep an eye on that and keep rolling there.","index":49,"end_time":161.98,"speaker_id":1,"start_time":159.42,"speaker_name":null},{"text":"The next thing is just ABM updates.","index":50,"end_time":165.18,"speaker_id":1,"start_time":163.1,"speaker_name":null},{"text":"So last week, Fahad, I talked to Jackie about this, but I went ahead and pulled where that contact was from from your call.","index":51,"end_time":172.98,"speaker_id":1,"start_time":165.26,"speaker_name":null},{"text":"So that came from a white collar lawyers spreadsheet that you guys had sent us.","index":52,"end_time":176.66,"speaker_id":1,"start_time":172.98,"speaker_name":null},{"text":"But did you have anything you wanted to add about that call or like how it went and if there''s any next steps?","index":53,"end_time":182.74,"speaker_id":1,"start_time":177.7,"speaker_name":null},{"text":"Yeah, so the call went very well.","index":54,"end_time":184.86,"speaker_id":2,"start_time":183.14,"speaker_name":null},{"text":"It was a short call.","index":55,"end_time":185.62,"speaker_id":2,"start_time":184.86,"speaker_name":null},{"text":"It wasn''t a demo, just an introduction.","index":56,"end_time":187.38,"speaker_id":2,"start_time":185.62,"speaker_name":null},{"text":"I Actually followed up with the lady yesterday on LinkedIn and told her that I sent her the email.","index":57,"end_time":193.42,"speaker_id":2,"start_time":187.38,"speaker_name":null},{"text":"I just wanted to make sure it didn''t go to spam or anything like that.","index":58,"end_time":196.26,"speaker_id":2,"start_time":193.42,"speaker_name":null},{"text":"And she responded.","index":59,"end_time":198.33,"speaker_id":2,"start_time":197.01,"speaker_name":null},{"text":"She sent it over to her, the co chair of the white collar department at DLA Piper.","index":60,"end_time":203.81,"speaker_id":2,"start_time":198.33,"speaker_name":null},{"text":"She said that hopefully during their next they have meetings that take place.","index":61,"end_time":211.09,"speaker_id":2,"start_time":205.09,"speaker_name":null},{"text":"I honestly don''t remember what she said, whether it was monthly or quarterly, where all the white collar folks get together on a call.","index":62,"end_time":218.77,"speaker_id":2,"start_time":211.73,"speaker_name":null},{"text":"And she wanted to make sure that we do a demo during that call so everybody would be there.","index":63,"end_time":223.09,"speaker_id":2,"start_time":218.93,"speaker_name":null},{"text":"That''s awesome.","index":64,"end_time":224.44,"speaker_id":1,"start_time":223.72,"speaker_name":null},{"text":"But I don''t have a timeline.","index":65,"end_time":226.52,"speaker_id":2,"start_time":224.52,"speaker_name":null},{"text":"I don''t know when to expect it.","index":66,"end_time":228.36,"speaker_id":2,"start_time":226.52,"speaker_name":null},{"text":"So it''s positive.","index":67,"end_time":230.76,"speaker_id":2,"start_time":228.52,"speaker_name":null},{"text":"It''s as long as the.","index":68,"end_time":232.2,"speaker_id":2,"start_time":230.76,"speaker_name":null},{"text":"It''s still a lead.","index":69,"end_time":233.32,"speaker_id":2,"start_time":232.36,"speaker_name":null},{"text":"So it''s still moving in the right direction.","index":70,"end_time":234.92,"speaker_id":2,"start_time":233.32,"speaker_name":null},{"text":"Yes.","index":71,"end_time":235.8,"speaker_id":1,"start_time":235.32,"speaker_name":null},{"text":"Yeah, that''s great to hear.","index":72,"end_time":237.16,"speaker_id":1,"start_time":236.04,"speaker_name":null},{"text":"I''m really happy to hear that.","index":73,"end_time":238.2,"speaker_id":1,"start_time":237.16,"speaker_name":null},{"text":"And hopefully it gets to the right people and you''re able to do that demo.","index":74,"end_time":241.6,"speaker_id":1,"start_time":238.2,"speaker_name":null},{"text":"So that''s good.","index":75,"end_time":242.44,"speaker_id":1,"start_time":241.6,"speaker_name":null},{"text":"Anytime you''re able to even get on a call with somebody is awesome.","index":76,"end_time":245.72,"speaker_id":1,"start_time":242.44,"speaker_name":null},{"text":"Sometimes people say they''re available and as you know, that doesn''t happen.","index":77,"end_time":249.56,"speaker_id":1,"start_time":246.52,"speaker_name":null},{"text":"So I''m happy to hear that.","index":78,"end_time":251.64,"speaker_id":1,"start_time":249.64,"speaker_name":null},{"text":"Just on the white.","index":79,"end_time":253.67,"speaker_id":2,"start_time":252.95,"speaker_name":null},{"text":"This row 43, this is from one of the spreadsheets that we sent you from the law.","index":80,"end_time":260.23,"speaker_id":2,"start_time":253.91,"speaker_name":null},{"text":"All the lawyers.","index":81,"end_time":261.27,"speaker_id":2,"start_time":260.39,"speaker_name":null},{"text":"Yeah, the ones that you guys send each week.","index":82,"end_time":265.31,"speaker_id":1,"start_time":263.51,"speaker_name":null},{"text":"I just was going through all of our spreadsheets to find where the contact.","index":83,"end_time":269.27,"speaker_id":1,"start_time":265.31,"speaker_name":null},{"text":"Came from or did we message them?","index":84,"end_time":271.35,"speaker_id":2,"start_time":269.35,"speaker_name":null},{"text":"This was a LinkedIn message through the ABM sequence and she, she most likely got an email as well.","index":85,"end_time":277.75,"speaker_id":1,"start_time":272.07,"speaker_name":null},{"text":"Um, but usually LinkedIn picks up easier because it''s more of like a personal way to interact with people.","index":86,"end_time":283.76,"speaker_id":1,"start_time":278.24,"speaker_name":null},{"text":"Um, but yeah, we enriched the list to pull her LinkedIn.","index":87,"end_time":287.48,"speaker_id":1,"start_time":284.08,"speaker_name":null},{"text":"So you guys give us the emails and then as soon as we get the emails from Jeffrey, we go ahead and enrich the list through Clay to find everybody''s LinkedIn address.","index":88,"end_time":295.2,"speaker_id":1,"start_time":287.48,"speaker_name":null},{"text":"Then we can add them to the campaign on the LinkedIn side of things.","index":89,"end_time":297.92,"speaker_id":1,"start_time":295.2,"speaker_name":null},{"text":"So that''s how we were able to contact her.","index":90,"end_time":300.08,"speaker_id":1,"start_time":297.92,"speaker_name":null},{"text":"Yeah, but I was just talking to Jackie.","index":91,"end_time":302.92,"speaker_id":1,"start_time":300.72,"speaker_name":null},{"text":"We were curious to find exactly what group.","index":92,"end_time":304.91,"speaker_id":1,"start_time":302.92,"speaker_name":null},{"text":"Group she came from.","index":93,"end_time":305.94,"speaker_id":1,"start_time":305.06,"speaker_name":null},{"text":"So I just went through all the spreadsheets to find.","index":94,"end_time":308.58,"speaker_id":1,"start_time":305.94,"speaker_name":null},{"text":"So yeah, just cool to see who''s responding and who it.","index":95,"end_time":313.7,"speaker_id":1,"start_time":309.38,"speaker_name":null},{"text":"Who the audience is towards.","index":96,"end_time":315.22,"speaker_id":1,"start_time":313.78,"speaker_name":null},{"text":"But yeah, so I talked to Jackie about this last week.","index":97,"end_time":319.58,"speaker_id":1,"start_time":316.34,"speaker_name":null},{"text":"I think that we did have one call obviously that went through, which is really great.","index":98,"end_time":323.94,"speaker_id":1,"start_time":319.58,"speaker_name":null},{"text":"However, I think it would be good to maybe utilize the new AI Investigator announcement.","index":99,"end_time":329.7,"speaker_id":1,"start_time":324.18,"speaker_name":null},{"text":"That we have to form a new sequence that we test with a smaller audience.","index":100,"end_time":333.78,"speaker_id":1,"start_time":329.7,"speaker_name":null},{"text":"Something.","index":101,"end_time":334.37,"speaker_id":1,"start_time":334.1,"speaker_name":null},{"text":"One of my ideas was with the contacts that we''ve received from all of our leads through the LinkedIn lead gen campaign forum.","index":102,"end_time":344.24,"speaker_id":1,"start_time":334.52,"speaker_name":null},{"text":"So we did see another lead come in this past weekend for the buyer''s guide.","index":103,"end_time":349.16,"speaker_id":1,"start_time":344.24,"speaker_name":null},{"text":"So I added that up here from the 16th and then so we have 91 leads from just this, 1, 8 leads from the data sheet and then 3 leads from the white collar case study.","index":104,"end_time":360.2,"speaker_id":1,"start_time":349.16,"speaker_name":null},{"text":"So what we can do.","index":105,"end_time":361.45,"speaker_id":1,"start_time":360.73,"speaker_name":null},{"text":"This was just one of my ideas is I created and sent Jackie.","index":106,"end_time":364.93,"speaker_id":1,"start_time":361.45,"speaker_name":null},{"text":"I don''t know if you had a chance to look at this yet, but I just created a two email sequence.","index":107,"end_time":369.13,"speaker_id":1,"start_time":364.93,"speaker_name":null},{"text":"Keep it short.","index":108,"end_time":369.77,"speaker_id":1,"start_time":369.13,"speaker_name":null},{"text":"Like we have been in a two LinkedIn message sequence where we just speak to this AI investigator announcement.","index":109,"end_time":376.29,"speaker_id":1,"start_time":369.77,"speaker_name":null},{"text":"And then Jackie Anna was working on that video to kind of walk through what it looks like and then kind of just entice them by talking about how it could work for them and their company.","index":110,"end_time":386.09,"speaker_id":1,"start_time":376.29,"speaker_name":null},{"text":"And then this way it.","index":111,"end_time":387.37,"speaker_id":1,"start_time":386.17,"speaker_name":null},{"text":"It gives something to the people, but it also kind of encourages a call to action to get back to you.","index":112,"end_time":392.9,"speaker_id":1,"start_time":387.62,"speaker_name":null},{"text":"And I thought it would be a good idea that instead of throwing it into our thousands of contact sequence that we already have to put it into a smaller campaign sequence so we can learn about the audience.","index":113,"end_time":402.7,"speaker_id":1,"start_time":392.9,"speaker_name":null},{"text":"So I figure maybe the leads would be good because those people have clicked a button to download your content.","index":114,"end_time":407.78,"speaker_id":1,"start_time":402.7,"speaker_name":null},{"text":"They have actively been engaged with your content.","index":115,"end_time":410.02,"speaker_id":1,"start_time":407.78,"speaker_name":null},{"text":"So that''s one route we could go as far as audience.","index":116,"end_time":412.98,"speaker_id":1,"start_time":410.5,"speaker_name":null},{"text":"The second thing we could do is if there was a particular group of people that you had in a spreadsheet or one of the spreadsheets you sent us and you''re like, this would be a good test audience.","index":117,"end_time":421.71,"speaker_id":1,"start_time":413.79,"speaker_name":null},{"text":"We could do the same thing with a different group and just kind of see how these interact people.","index":118,"end_time":426.75,"speaker_id":1,"start_time":421.71,"speaker_name":null},{"text":"If we get more responses, if this is more of like something that people are interested in than just these data sheets, these ebooks that we''re offering.","index":119,"end_time":434.03,"speaker_id":1,"start_time":426.75,"speaker_name":null},{"text":"This is kind of a specific thing.","index":120,"end_time":436.27,"speaker_id":1,"start_time":434.35,"speaker_name":null},{"text":"And the AI investigator seems to be like a really cool tool that may resonate more with this particular audience.","index":121,"end_time":441.79,"speaker_id":1,"start_time":436.27,"speaker_name":null},{"text":"So.","index":122,"end_time":442.27,"speaker_id":1,"start_time":441.87,"speaker_name":null},{"text":"And also on top of that, I just want to let you know that we have seen one lead come through.","index":123,"end_time":448.36,"speaker_id":1,"start_time":443.32,"speaker_name":null},{"text":"Yes, but we want you to get more leads.","index":124,"end_time":450.04,"speaker_id":1,"start_time":448.36,"speaker_name":null},{"text":"So I talked with our leadership team here and they want to gift you the points for this because we really do want to see you guys get leads through.","index":125,"end_time":456.36,"speaker_id":1,"start_time":450.04,"speaker_name":null},{"text":"So we would gift you the points to get this new sequence up and running and see how we can kind of get more feedback from the audience.","index":126,"end_time":465.32,"speaker_id":1,"start_time":456.68,"speaker_name":null},{"text":"Since the one we have right now has been running for a bit.","index":127,"end_time":468.08,"speaker_id":1,"start_time":465.4,"speaker_name":null},{"text":"So this is kind of a good idea to see if we can change it.","index":128,"end_time":470.32,"speaker_id":1,"start_time":468.08,"speaker_name":null},{"text":"So what do you think about all that?","index":129,"end_time":471.52,"speaker_id":1,"start_time":470.32,"speaker_name":null},{"text":"I know I just dumped a lot on you.","index":130,"end_time":473.46,"speaker_id":1,"start_time":471.52,"speaker_name":null},{"text":"No, I appreciate that.","index":131,"end_time":475.14,"speaker_id":2,"start_time":474.02,"speaker_name":null},{"text":"I''m just wondering whether the leads.","index":132,"end_time":476.78,"speaker_id":2,"start_time":475.14,"speaker_name":null},{"text":"Because from memory, from the 91 leads that we got, only a handful were maybe more than maybe a dozen or so that were from, you know, major law firms.","index":133,"end_time":489.22,"speaker_id":2,"start_time":476.78,"speaker_name":null},{"text":"And I''m just wondering if we look at historically what we have.","index":134,"end_time":494.94,"speaker_id":2,"start_time":489.22,"speaker_name":null},{"text":"So this lady from the dla, Piper, is with the White Collar team.","index":135,"end_time":498.34,"speaker_id":2,"start_time":494.94,"speaker_name":null},{"text":"The wild people that reached out to us were from the White Collar team.","index":136,"end_time":502.53,"speaker_id":2,"start_time":498.93,"speaker_name":null},{"text":"I''m just thinking, should we focus on only White Collar as a starting point?","index":137,"end_time":514.29,"speaker_id":2,"start_time":504.37,"speaker_name":null},{"text":"And it could be.","index":138,"end_time":516.13,"speaker_id":2,"start_time":514.53,"speaker_name":null},{"text":"It could be these 91 people.","index":139,"end_time":517.97,"speaker_id":2,"start_time":516.45,"speaker_name":null},{"text":"I mean, I don''t mind, but I.","index":140,"end_time":520.05,"speaker_id":2,"start_time":517.97,"speaker_name":null},{"text":"We wanted to get your feedback because, you know, the people in the titles, the best.","index":141,"end_time":524.33,"speaker_id":1,"start_time":520.21,"speaker_name":null},{"text":"Like, we.","index":142,"end_time":524.85,"speaker_id":1,"start_time":524.33,"speaker_name":null},{"text":"We''re just seeing the data come through on these sheets.","index":143,"end_time":527.17,"speaker_id":1,"start_time":524.85,"speaker_name":null},{"text":"But if you''re saying like these aren''t companies that you think would be the best option, then let''s test with a different audience.","index":144,"end_time":533.12,"speaker_id":1,"start_time":527.17,"speaker_name":null},{"text":"Like you''re saying, if White Collar is something that you think would be more resonant with this offer, then let''s do that.","index":145,"end_time":538.76,"speaker_id":1,"start_time":533.12,"speaker_name":null},{"text":"Whatever you think is best as far as audience.","index":146,"end_time":541,"speaker_id":1,"start_time":539,"speaker_name":null},{"text":"Look at this list in front of you.","index":147,"end_time":543,"speaker_id":2,"start_time":541.72,"speaker_name":null},{"text":"The top three I wouldn''t even circle back to, but PwC might be worthwhile, Right?","index":148,"end_time":547.72,"speaker_id":2,"start_time":543,"speaker_name":null},{"text":"Then future interns, Colorado School of Mines, Phoenix Emergency Care, University of North Texas.","index":149,"end_time":555.08,"speaker_id":2,"start_time":548.2,"speaker_name":null},{"text":"These are, you know, maybe KK Consulting.","index":150,"end_time":558.98,"speaker_id":2,"start_time":555.66,"speaker_name":null},{"text":"I. I don''t know what''s the size AT T, but then you have an email that does not represent att and you don''t know whether this is AT T or this is actually somebody else, so.","index":151,"end_time":569.7,"speaker_id":2,"start_time":558.98,"speaker_name":null},{"text":"Yeah, but there''s a few names that did stand out in this, but unfortunately the majority did not.","index":152,"end_time":581.98,"speaker_id":2,"start_time":569.7,"speaker_name":null},{"text":"Yeah, and we can always add like ad hoc them in.","index":153,"end_time":586.51,"speaker_id":1,"start_time":583.59,"speaker_name":null},{"text":"So if there are a couple like you''re saying that you think would be good, let''s add them to the lawyers list that you think would be a good target audience.","index":154,"end_time":592.43,"speaker_id":1,"start_time":586.51,"speaker_name":null},{"text":"So we can just add them in as emails to the spreadsheet that we end up using for the.","index":155,"end_time":597.67,"speaker_id":1,"start_time":592.43,"speaker_name":null},{"text":"For the updated sequence.","index":156,"end_time":599.03,"speaker_id":1,"start_time":597.67,"speaker_name":null},{"text":"Yeah, I guess.","index":157,"end_time":600.99,"speaker_id":2,"start_time":600.15,"speaker_name":null},{"text":"So is there a particular group that you''d want to put together in a spreadsheet as far as the White Collar lawyers?","index":158,"end_time":606.47,"speaker_id":1,"start_time":600.99,"speaker_name":null},{"text":"Or do you think any of the spreadsheets that we''ve gotten so far from Jeffrey, would be like a good way to test the new New Sequen.","index":159,"end_time":613.83,"speaker_id":1,"start_time":606.47,"speaker_name":null},{"text":"I think, I think the way Jeffrey, when, when I instructed them to work on this was by city.","index":160,"end_time":619.15,"speaker_id":2,"start_time":614.19,"speaker_name":null},{"text":"So I would, you know, I, I look at New York White Collar and start there.","index":161,"end_time":624.35,"speaker_id":2,"start_time":619.55,"speaker_name":null},{"text":"Okay.","index":162,"end_time":625.39,"speaker_id":1,"start_time":624.83,"speaker_name":null},{"text":"It doesn''t have to be every single state, but, you know, a lot of the financial crimes does take place in New York or it''s being litigated in New York.","index":163,"end_time":635.87,"speaker_id":2,"start_time":626.91,"speaker_name":null},{"text":"So a lot of the lawyers are from New York and maybe that''s a good starting point.","index":164,"end_time":640.43,"speaker_id":2,"start_time":635.87,"speaker_name":null},{"text":"Okay, yeah, idea.","index":165,"end_time":642.71,"speaker_id":1,"start_time":641.11,"speaker_name":null},{"text":"That sounds good.","index":166,"end_time":644.47,"speaker_id":1,"start_time":643.59,"speaker_name":null},{"text":"And then on the video, Taylor.","index":167,"end_time":646.43,"speaker_id":0,"start_time":644.71,"speaker_name":null},{"text":"So I created it, but it turns out we''re making a change to the ui, so I have to reshoot it, but we''ll have that soon.","index":168,"end_time":652.79,"speaker_id":0,"start_time":646.43,"speaker_name":null},{"text":"And it''s not that.","index":169,"end_time":653.91,"speaker_id":0,"start_time":652.79,"speaker_name":null},{"text":"Just to, to reiterate, it''s not just AI Investigator, it''s the happy path that shows how you use AI Investigator to start and then that leads you to the parties tab where you can look at the party and then to the transactions tab where you can go immediately into the suspicious transaction.","index":170,"end_time":669.27,"speaker_id":0,"start_time":654.47,"speaker_name":null},{"text":"So you can go from like high level all.","index":171,"end_time":671.54,"speaker_id":0,"start_time":669.27,"speaker_name":null},{"text":"All the way down to immediately investigating in within two minutes.","index":172,"end_time":674.41,"speaker_id":0,"start_time":671.61,"speaker_name":null},{"text":"So that''s the.","index":173,"end_time":675.45,"speaker_id":0,"start_time":674.65,"speaker_name":null},{"text":"It''s just kind of the.","index":174,"end_time":676.49,"speaker_id":0,"start_time":675.45,"speaker_name":null},{"text":"A teaser of the UI itself.","index":175,"end_time":678.33,"speaker_id":0,"start_time":676.49,"speaker_name":null},{"text":"But I don''t think there''s anything wrong with highlighting the AI investigator in the email sequence.","index":176,"end_time":683.77,"speaker_id":0,"start_time":678.49,"speaker_name":null},{"text":"I just want to.","index":177,"end_time":684.69,"speaker_id":0,"start_time":683.93,"speaker_name":null},{"text":"I''ll make little tweaks to the wording to say that.","index":178,"end_time":687.25,"speaker_id":0,"start_time":684.69,"speaker_name":null},{"text":"We''ll show you how this, the AI Investigator kicks off your.","index":179,"end_time":690.01,"speaker_id":0,"start_time":687.25,"speaker_name":null},{"text":"Your investigation.","index":180,"end_time":690.97,"speaker_id":0,"start_time":690.01,"speaker_name":null},{"text":"So.","index":181,"end_time":691.65,"speaker_id":0,"start_time":691.29,"speaker_name":null},{"text":"Right.","index":182,"end_time":691.97,"speaker_id":1,"start_time":691.65,"speaker_name":null},{"text":"Anyway, I''ll be.","index":183,"end_time":692.89,"speaker_id":0,"start_time":691.97,"speaker_name":null},{"text":"Just FYI.","index":184,"end_time":694.01,"speaker_id":0,"start_time":692.89,"speaker_name":null},{"text":"Yeah, that makes sense.","index":185,"end_time":695.81,"speaker_id":1,"start_time":694.81,"speaker_name":null},{"text":"Y.","index":186,"end_time":696.09,"speaker_id":1,"start_time":695.81,"speaker_name":null},{"text":"If you.","index":187,"end_time":696.57,"speaker_id":1,"start_time":696.09,"speaker_name":null},{"text":"If there''s anything in here that like you''re saying, if you have new elements to the video, we can just change the copy around that.","index":188,"end_time":701.86,"speaker_id":1,"start_time":696.57,"speaker_name":null},{"text":"But that''ll be a good thing to, to use, so.","index":189,"end_time":705.06,"speaker_id":1,"start_time":701.86,"speaker_name":null},{"text":"Great.","index":190,"end_time":706.1,"speaker_id":1,"start_time":705.7,"speaker_name":null},{"text":"Well, yeah, we''ll go ahead and pull some specifics for the white collar audience for New York and then I''ll send that over to you just to double check.","index":191,"end_time":713.14,"speaker_id":1,"start_time":706.1,"speaker_name":null},{"text":"And then we''ll just wait for the video and a couple refinements on the copy and then we can go from there.","index":192,"end_time":718.58,"speaker_id":1,"start_time":713.94,"speaker_name":null},{"text":"But it''ll be good to just kind of a B test a couple different options as far as messaging so we can see what gets the most feedback.","index":193,"end_time":724.95,"speaker_id":1,"start_time":718.66,"speaker_name":null},{"text":"And then I have those LinkedIn messages at the bottom too, if you just want to take a look at those when you go through it.","index":194,"end_time":730.79,"speaker_id":1,"start_time":726.15,"speaker_name":null},{"text":"But yeah, sounds good.","index":195,"end_time":733.51,"speaker_id":1,"start_time":731.43,"speaker_name":null},{"text":"Excellent.","index":196,"end_time":734.95,"speaker_id":2,"start_time":734.23,"speaker_name":null},{"text":"And then as far as paid media, so for the schedule, a demo campaign, we have a lot of pressions and clicks on this one.","index":197,"end_time":741.99,"speaker_id":1,"start_time":735.99,"speaker_name":null},{"text":"I shared this with Jackie last week.","index":198,"end_time":743.67,"speaker_id":1,"start_time":741.99,"speaker_name":null},{"text":"We have one of the ads that performs the highest of all of them.","index":199,"end_time":747.39,"speaker_id":1,"start_time":743.83,"speaker_name":null},{"text":"So this one has been the highest performing one.","index":200,"end_time":749.83,"speaker_id":1,"start_time":747.39,"speaker_name":null},{"text":"I think it''s at 11,000 by itself and the rest are kind of like four or five.","index":201,"end_time":753.83,"speaker_id":1,"start_time":749.83,"speaker_name":null},{"text":"Um, so this one is specifically the imagery I think maybe is pulling people in.","index":202,"end_time":759.77,"speaker_id":1,"start_time":754.49,"speaker_name":null},{"text":"But also just this is the one that has the most clicks and impressions.","index":203,"end_time":763.81,"speaker_id":1,"start_time":760.41,"speaker_name":null},{"text":"So just something to look back on.","index":204,"end_time":766.49,"speaker_id":1,"start_time":763.81,"speaker_name":null},{"text":"Doesn''t have any likes or reposts.","index":205,"end_time":769.21,"speaker_id":2,"start_time":767.13,"speaker_name":null},{"text":"Yes.","index":206,"end_time":770.37,"speaker_id":1,"start_time":769.93,"speaker_name":null},{"text":"So it''s, it''s based on just impressions of people that are clicking this button that are going to the schedule.","index":207,"end_time":775.93,"speaker_id":1,"start_time":770.37,"speaker_name":null},{"text":"A demo.","index":208,"end_time":776.57,"speaker_id":1,"start_time":775.93,"speaker_name":null},{"text":"Oop, sorry, is it here?","index":209,"end_time":778.89,"speaker_id":1,"start_time":777.29,"speaker_name":null},{"text":"And, and it doesn''t always mean that people are necessarily interacting with it.","index":210,"end_time":783.43,"speaker_id":1,"start_time":778.89,"speaker_name":null},{"text":"It''s just kind of who is viewing it and then also like clicking the button.","index":211,"end_time":787.11,"speaker_id":1,"start_time":783.43,"speaker_name":null},{"text":"I can see.","index":212,"end_time":787.99,"speaker_id":1,"start_time":787.35,"speaker_name":null},{"text":"Sorry, when was this posted?","index":213,"end_time":792.15,"speaker_id":2,"start_time":789.99,"speaker_name":null},{"text":"The schedule A demo one launched back in, I think November end.","index":214,"end_time":797.39,"speaker_id":1,"start_time":792.47,"speaker_name":null},{"text":"November.","index":215,"end_time":797.79,"speaker_id":1,"start_time":797.39,"speaker_name":null},{"text":"December.","index":216,"end_time":798.19,"speaker_id":1,"start_time":797.79,"speaker_name":null},{"text":"But I can send you the specific breakdown of the data after the meeting if that''s helpful.","index":217,"end_time":804.23,"speaker_id":1,"start_time":798.19,"speaker_name":null},{"text":"I reposted on my page because it just has more followers.","index":218,"end_time":808.31,"speaker_id":2,"start_time":804.55,"speaker_name":null},{"text":"There are several of those ads.","index":219,"end_time":810.11,"speaker_id":1,"start_time":808.31,"speaker_name":null},{"text":"So.","index":220,"end_time":810.23,"speaker_id":1,"start_time":810.11,"speaker_name":null},{"text":"So we have not just one variation.","index":221,"end_time":812.42,"speaker_id":1,"start_time":810.46,"speaker_name":null},{"text":"So that''s one particular variation.","index":222,"end_time":814.06,"speaker_id":1,"start_time":812.42,"speaker_name":null},{"text":"So you probably did.","index":223,"end_time":815.42,"speaker_id":1,"start_time":814.22,"speaker_name":null},{"text":"We have like a bunch of different versions of the same.","index":224,"end_time":817.82,"speaker_id":1,"start_time":815.42,"speaker_name":null},{"text":"Yeah, okay.","index":225,"end_time":819.82,"speaker_id":2,"start_time":818.3,"speaker_name":null},{"text":"No, you''re good.","index":226,"end_time":820.94,"speaker_id":1,"start_time":820.06,"speaker_name":null},{"text":"There are like I think four or five different versions of the images and also the copy that we have in there.","index":227,"end_time":826.22,"speaker_id":1,"start_time":821.1,"speaker_name":null},{"text":"So I was.","index":228,"end_time":828.1,"speaker_id":0,"start_time":826.22,"speaker_name":null},{"text":"And my point when I saw that one last week when we talked about it is I. I suspect that maybe the reason that one had so many clicks is because it doesn''t actually mention financial investigations in it.","index":229,"end_time":837.82,"speaker_id":0,"start_time":828.1,"speaker_name":null},{"text":"It''s kind of broad and vague and so people who maybe weren''t qualified were the right were people were clicking on it and that''s why they didn''t actually schedule a demo.","index":230,"end_time":846.52,"speaker_id":0,"start_time":837.9,"speaker_name":null},{"text":"So because it just talks about your data and it doesn''t really say what kind of data.","index":231,"end_time":852.84,"speaker_id":0,"start_time":846.84,"speaker_name":null},{"text":"It doesn''t.","index":232,"end_time":853.8,"speaker_id":0,"start_time":853.24,"speaker_name":null},{"text":"It doesn''t clarify that it''s about financial investigations, which is, you know, not necessarily a bad thing.","index":233,"end_time":858.32,"speaker_id":0,"start_time":853.8,"speaker_name":null},{"text":"But I suspect a lot of those clicks are from people who were thinking that it maybe was some other kind of data.","index":234,"end_time":863.48,"speaker_id":0,"start_time":858.32,"speaker_name":null},{"text":"Yeah, that could, that could be the case for sure.","index":235,"end_time":867.65,"speaker_id":1,"start_time":865.57,"speaker_name":null},{"text":"But I can break down the specific versions that we have of all the different ads and send that to you too.","index":236,"end_time":873.41,"speaker_id":1,"start_time":868.45,"speaker_name":null},{"text":"So you can see the breakdown.","index":237,"end_time":874.61,"speaker_id":1,"start_time":873.41,"speaker_name":null},{"text":"And then we''ve talked about the lead gen campaigns.","index":238,"end_time":878.13,"speaker_id":1,"start_time":876.21,"speaker_name":null},{"text":"We just went through those and then the video ad.","index":239,"end_time":880.41,"speaker_id":1,"start_time":878.13,"speaker_name":null},{"text":"So I just wanted to update you here.","index":240,"end_time":881.45,"speaker_id":1,"start_time":880.41,"speaker_name":null},{"text":"This is the video ad we''ve had running for a bit now with the original video that we created.","index":241,"end_time":886.25,"speaker_id":1,"start_time":881.45,"speaker_name":null},{"text":"I wasn''t sure if it would be of interest to you guys to maybe switch this.","index":242,"end_time":889.53,"speaker_id":1,"start_time":886.25,"speaker_name":null},{"text":"Pause this one out and switch it with the new video.","index":243,"end_time":891.37,"speaker_id":1,"start_time":889.53,"speaker_name":null},{"text":"Or if you''d like to keep the.","index":244,"end_time":892.69,"speaker_id":1,"start_time":891.37,"speaker_name":null},{"text":"The same, like, branded one that we originally started with.","index":245,"end_time":895.49,"speaker_id":1,"start_time":892.77,"speaker_name":null},{"text":"I know this one''s been running for a little bit, and I know we just finished up the last one that you added to the website, so just wanted to see if that was of interest to you guys to.","index":246,"end_time":903.63,"speaker_id":1,"start_time":896.75,"speaker_name":null},{"text":"To promote the new one on procurement.","index":247,"end_time":906.03,"speaker_id":1,"start_time":903.87,"speaker_name":null},{"text":"Sure.","index":248,"end_time":909.31,"speaker_id":1,"start_time":908.91,"speaker_name":null},{"text":"Yeah.","index":249,"end_time":910.91,"speaker_id":1,"start_time":910.43,"speaker_name":null},{"text":"Why can''t we promote both?","index":250,"end_time":913.71,"speaker_id":2,"start_time":912.27,"speaker_name":null},{"text":"We can.","index":251,"end_time":914.67,"speaker_id":1,"start_time":914.11,"speaker_name":null},{"text":"We definitely can.","index":252,"end_time":915.55,"speaker_id":1,"start_time":914.75,"speaker_name":null},{"text":"We can add the other one in simultaneously.","index":253,"end_time":917.43,"speaker_id":1,"start_time":915.55,"speaker_name":null},{"text":"We don''t necessarily have to pause the current one.","index":254,"end_time":919.15,"speaker_id":1,"start_time":917.43,"speaker_name":null},{"text":"I just noticed that we had this one running for a bit, so if we wanted to change it out.","index":255,"end_time":922.55,"speaker_id":1,"start_time":919.47,"speaker_name":null},{"text":"But we can do both.","index":256,"end_time":923.15,"speaker_id":1,"start_time":922.55,"speaker_name":null},{"text":"It''s the same time, too.","index":257,"end_time":924.27,"speaker_id":1,"start_time":923.15,"speaker_name":null},{"text":"I just know that we just completed that and added it to the website.","index":258,"end_time":926.99,"speaker_id":1,"start_time":924.27,"speaker_name":null},{"text":"So if we wanted to throw that one in, I know it''s a.","index":259,"end_time":929.11,"speaker_id":1,"start_time":926.99,"speaker_name":null},{"text":"It''s a great video and it''s a little bit shorter, too, so that may also be good for engagement.","index":260,"end_time":933.63,"speaker_id":1,"start_time":929.11,"speaker_name":null},{"text":"What do you think, Jackie?","index":261,"end_time":936.83,"speaker_id":2,"start_time":935.55,"speaker_name":null},{"text":"Yeah, absolutely.","index":262,"end_time":937.71,"speaker_id":0,"start_time":936.91,"speaker_name":null},{"text":"I mean, those.","index":263,"end_time":938.27,"speaker_id":0,"start_time":937.71,"speaker_name":null},{"text":"There are two different audiences.","index":264,"end_time":939.469,"speaker_id":0,"start_time":938.27,"speaker_name":null},{"text":"One is white collar, one is procurement, so we want to be making sure that we''re hitting both.","index":265,"end_time":943.47,"speaker_id":0,"start_time":939.469,"speaker_name":null},{"text":"Great.","index":266,"end_time":944.63,"speaker_id":1,"start_time":944.27,"speaker_name":null},{"text":"Yeah, I can work with our payment specialists and.","index":267,"end_time":946.95,"speaker_id":1,"start_time":944.63,"speaker_name":null},{"text":"And get that running too.","index":268,"end_time":948.19,"speaker_id":1,"start_time":946.95,"speaker_name":null},{"text":"I know that we worked hard on that one, so that one''s a good one too.","index":269,"end_time":950.76,"speaker_id":1,"start_time":948.19,"speaker_name":null},{"text":"And like I said, it''s a little bit shorter, so easier to digest sometimes than the longer ones.","index":270,"end_time":954.68,"speaker_id":1,"start_time":950.76,"speaker_name":null},{"text":"So I''ll let you know when we get that one rolling.","index":271,"end_time":957.32,"speaker_id":1,"start_time":955,"speaker_name":null},{"text":"Great.","index":272,"end_time":958.2,"speaker_id":1,"start_time":957.8,"speaker_name":null},{"text":"Great.","index":273,"end_time":959.4,"speaker_id":1,"start_time":959,"speaker_name":null},{"text":"So then, just the last couple things, we''re wrapping up the edits on those data sheets.","index":274,"end_time":963.4,"speaker_id":1,"start_time":959.72,"speaker_name":null},{"text":"I''ll send those over to you soon.","index":275,"end_time":964.92,"speaker_id":1,"start_time":963.4,"speaker_name":null},{"text":"And then the new campaign and audience that we''re talking about, I''ll work on the white collar side of things on our end for the audience.","index":276,"end_time":971.48,"speaker_id":1,"start_time":965.88,"speaker_name":null},{"text":"And then Jackie will look for any edits in the video from you.","index":277,"end_time":974.68,"speaker_id":1,"start_time":971.48,"speaker_name":null},{"text":"And then, Fahad, whenever you can get some topic ideas to us, we''ll get those implemented in and then hopeful we can get some things scheduled out to your page.","index":278,"end_time":982.74,"speaker_id":1,"start_time":974.68,"speaker_name":null},{"text":"Yeah, that''s what we have going on on our end.","index":279,"end_time":986.5,"speaker_id":1,"start_time":984.66,"speaker_name":null},{"text":"But I will keep you updated in Slack with anything else that comes up.","index":280,"end_time":989.94,"speaker_id":1,"start_time":986.5,"speaker_name":null},{"text":"And yeah, that''s all we''ve got for today.","index":281,"end_time":992.82,"speaker_id":1,"start_time":989.94,"speaker_name":null},{"text":"Good.","index":282,"end_time":993.22,"speaker_id":1,"start_time":992.82,"speaker_name":null},{"text":"Thanks so much.","index":283,"end_time":994.1,"speaker_id":1,"start_time":993.3,"speaker_name":null},{"text":"Awesome.","index":284,"end_time":994.7,"speaker_id":1,"start_time":994.18,"speaker_name":null},{"text":"Hope you guys have a good rest of the day.","index":285,"end_time":996.1,"speaker_id":1,"start_time":994.7,"speaker_name":null},{"text":"You too.","index":286,"end_time":996.66,"speaker_id":0,"start_time":996.1,"speaker_name":null},{"text":"Bye.","index":287,"end_time":997.219,"speaker_id":1,"start_time":996.739,"speaker_name":null},{"text":"Bye.","index":288,"end_time":997.7,"speaker_id":1,"start_time":997.22,"speaker_name":null}],"dateString":"2026-01-23T22:03:04.000Z","host_email":null,"meeting_link":null,"participants":[],"transcript_url":"https://app.fireflies.ai/view/01KFPE3R065TT50977VKXE220J","organizer_email":"taylor.doerbaum@marketersindemand.com"}'::jsonb,
  '{"label":"positive","confidence":0.92,"bullets":["Reported uptick in social followers; new posts scheduled through early February to sustain engagement.","Fahad''s call led to follow-up with DLA Piper; potential white collar demo being coordinated.","Proposed new AI Investigator campaign sequence targeting engaged LinkedIn leads and white collar lawyers.","Ad performance reviewed; most clicked ad may lack clarity on financial investigations, prompting refinements.","New procurement-focused video ad to run alongside current one to reach distinct professional audiences."],"highlights":[{"quote":"She wanted to make sure that we do a demo during that call so everybody would be there.","speaker":"Fahad"},{"quote":"We want you to get more leads... we would gift you the points to get this new sequence up and running.","speaker":"Unknown"},{"quote":"We''ll go ahead and pull some specifics for the white collar audience for New York.","speaker":"Unknown"}],"topics":["campaign","targeting","leadgen","ads","video"],"model":"openai/gpt-4-1106-preview","version":1,"generated_at":"2026-01-23T00:43:00Z"}'::jsonb,
  '{"fireflies_summary":null,"migrated_from":"contract_meetings","original_id":"f0fd0f63-9d57-4b0e-9bfd-2e03f82b6775","master_marketer":{"status":"migrated"}}'::jsonb,
  '2026-01-23 22:04:54.455931+00',
  '2026-01-23 22:04:54.455931+00'
);

