-- Meeting: taylor.doerbaum@marketersindemand.com - Tue, 20 Jan 2026 12:03:26 CST - Untitled (2026-01-20 18:03:26+00)
WITH new_meeting AS (
  INSERT INTO compass_meetings (contract_id, meeting_date, source, external_id, title, participants, duration_seconds, recording_url, transcript, sentiment, raw_metadata, created_at, updated_at)
  VALUES (
    'c8bd9166-2a8e-4824-9bbb-304f1d8ce014',
    '2026-01-20 18:03:26+00',
    'fireflies',
    '01KFE96T3DRQ4REKSQX8XX1JYW',
    'taylor.doerbaum@marketersindemand.com - Tue, 20 Jan 2026 12:03:26 CST - Untitled',
    '{"Nigel Sapp","Taylor Doerbaum"}'::text[],
    267,
    'https://us02web.zoom.us/j/87308650037?pwd=bM6sbrwhFcAqarZfIvkukcaiz8joek.1',
    '{"id":"01KFE96T3DRQ4REKSQX8XX1JYW","title":"taylor.doerbaum@marketersindemand.com - Tue, 20 Jan 2026 12:03:26 CST - Untitled","summary":{"notes":"## **Podcast Publishing and Content Strategy**\n\nThe team plans to organize existing and future podcast episodes into distinct seasonal batches to clarify content strategy and scheduling.\n\n- **Season one will remain open for additional episode uploads**, while all new episodes will be grouped under season two to streamline content delivery and audience tracking (02:10)  \n    - Nigel Sapp is preparing to send one new episode and has an intern reviewing backlog episodes for release  \n    - This phased publishing allows better management of content flow and listener engagement metrics  \n    - The approach aligns with the goal to maintain audience interest while managing internal review capacity  \n    - Taylor Doerbaum will set up season two on the Buzzsprout platform once new episodes are ready  \n\n- **The publishing schedule is shifting to a biweekly cadence**, reducing the monthly episode count from ten to five to match new meeting frequencies and workload (03:26)  \n    - This adjustment lowers monthly charges and frees up unused production points for other projects like design or accounting boards  \n    - Taylor highlighted the flexibility to repurpose extra points for additional support, providing strategic resource leverage  \n    - Nigel emphasized that current focus is on broader strategy and year planning rather than frequent podcast production  \n    - This shift supports better resource allocation aligned with evolving priorities and workload realities  \n\n## **Performance Metrics and Audience Engagement**\n\nRecent episode performance shows continued growth and listener interest, validating content strategy and providing insights for future planning.\n\n- **Season one episodes experienced a notable uptick in listener engagement**, particularly on episodes one, nine, and the finale, indicating strong audience pull for these segments (01:25)  \n    - Taylor shared updated listening stats that showed new listeners joining over time, reinforcing content longevity  \n    - Nigel observed that the popularity of early and late episodes aligns with natural audience behaviors around introductions and conclusions  \n    - These insights provide a basis for prioritizing similar content structures in future episodes  \n    - Continued performance tracking will guide content refinement and marketing efforts  \n\n- **Ongoing monitoring and sharing of listener data remain key to strategic decision-making**, with Taylor committed to sending updated stats regularly (03:50)  \n    - Transparent data sharing strengthens cross-team alignment on content impact and audience trends  \n    - It supports iterative adjustments to production and marketing strategies based on real-time feedback  \n    - This practice fosters proactive content optimization and stakeholder engagement  \n    - It also helps justify investment and resource allocation decisions  \n\n## **Resource Allocation and Team Roles**\n\nInternal team adjustments and clearer task assignments are helping streamline podcast production and review processes.\n\n- **Nigel introduced a new intern to take on episode review duties**, delegating backlog listening tasks to accelerate workflow (02:36)  \n    - This move distributes workload effectively and enables Nigel to focus on strategic planning  \n    - The intern’s involvement also helps scale review capacity without adding external costs  \n    - It supports timely episode releases and improves content quality through thorough review  \n    - This delegation reflects a pragmatic approach to resource management amid shifting priorities  \n\n- **The marketing team recently held an offsite to align on yearly goals**, reflecting a commitment to strategic clarity and team cohesion (00:18)  \n    - Nigel described the offsite as successful and energizing, setting a positive tone for the year  \n    - Such gatherings support stronger communication and shared vision across marketing functions  \n    - They help prepare the team for upcoming projects and workload shifts  \n    - The emphasis on routines post-offsite signals a return to focused execution  \n\n## **Financial and Contractual Adjustments**\n\nAdjustments in meeting frequency and production points are designed to optimize budget use and operational efficiency.\n\n- **Reducing meeting frequency to biweekly halves monthly production points and associated charges**, aligning costs with actual content output (03:26)  \n    - This change provides budgetary relief and creates capacity for other initiatives within the same contract  \n    - Taylor framed this as an opportunity to allocate points to new projects, such as design or accounting support  \n    - The adjustment improves cost-effectiveness while maintaining service flexibility  \n    - It reflects responsive contract management based on evolving client needs  \n\n- **Taylor communicated this update proactively to ensure Nigel’s team can plan resource use effectively**, avoiding surprises and enabling strategic decisions (03:26)  \n    - Clear communication of scope and billing changes reinforces trust and transparency  \n    - It encourages clients to explore additional services within existing agreements  \n    - This openness supports long-term partnership growth and satisfaction  \n    - It also enables smoother operational planning on both sides  \n\n## **Strategic Focus and Future Planning**\n\nThe leadership is prioritizing long-term strategy and operational alignment over short-term content output to set a strong foundation for the year.\n\n- **Nigel emphasized current efforts on broad strategy and annual structuring**, deprioritizing immediate podcast production to focus on sustainable growth (03:42)  \n    - This shift aims to clarify priorities and better allocate resources through the year  \n    - It allows the team to evaluate market conditions and competitive positioning before scaling content  \n    - The approach reflects a thoughtful balance between production demands and strategic vision  \n    - It prepares the company for more impactful initiatives later in the year  \n\n- **Taylor expressed readiness to support emerging needs with flexible resources**, reinforcing partnership strength and responsiveness (03:39)  \n    - This support framework ensures the team can adapt to changing priorities without delay  \n    - It promotes agility and collaborative problem-solving  \n    - The ongoing open dialogue helps identify new opportunities for value creation  \n    - It builds confidence in meeting both short- and long-term goals collaboratively","outline":null,"keywords":["marketing off-site","podcast statistics","season two launch","episode backlog","meeting cadence change","project points adjustment"],"overview":"- **Podcast Content Strategy:** Organizing podcasts into seasons enhances clarity and content delivery for audience engagement and tracking.\n\n- **Biweekly Publishing Strategy:** Reducing episodes from 10 to 5 monthly saves costs and reallocates resources for other projects.\n\n- **Listener Engagement Metrics:** Season one saw increased engagement, especially in episodes one, nine, and the finale, guiding future content.\n\n- **Intern Support Role:** An intern is helping with episode reviews, enabling more strategic focus and improving content quality.\n\n- **Budget Optimization:** Reduced meetings correlate with fewer production points, creating budget relief for other initiatives and enhancing efficiency.\n\n- **Long-term Strategic Focus:** Prioritizing strategy over short-term output prepares the team for impactful initiatives and sustainable growth.","action_items":"\n**Nigel Sapp**\nSend one new podcast episode for publishing (02:36)\nReview backlog of completed episodes with intern and send for editing/approval before end of the week (02:36)\n\n**Taylor Doerbaum**\nSet up season two on Buzzsprout for upcoming new episodes when published (02:10)\nReduce monthly points and adjust billing to reflect biweekly meeting schedule (02:59)\nSend updated podcast performance statistics to Nigel (03:56)\nMonitor and communicate about any pending episode updates or new content from Nigel (03:56)\n"},"duration":4.449999809265137,"speakers":[{"id":0,"name":"Nigel Sapp"},{"id":1,"name":"Taylor Doerbaum"}],"sentences":[{"text":"It going good.","index":0,"end_time":1.4,"speaker_id":0,"start_time":0.24,"speaker_name":"Nigel Sapp"},{"text":"How are you doing?","index":1,"end_time":2.08,"speaker_id":1,"start_time":1.4,"speaker_name":"Taylor Doerbaum"},{"text":"Doing well.","index":2,"end_time":3.4,"speaker_id":0,"start_time":2.8,"speaker_name":"Nigel Sapp"},{"text":"Give me one sec.","index":3,"end_time":4.08,"speaker_id":0,"start_time":3.4,"speaker_name":"Nigel Sapp"},{"text":"Yes, I am doing well.","index":4,"end_time":10.08,"speaker_id":0,"start_time":8.32,"speaker_name":"Nigel Sapp"},{"text":"How have you been?","index":5,"end_time":11.52,"speaker_id":0,"start_time":10.72,"speaker_name":"Nigel Sapp"},{"text":"Good.","index":6,"end_time":12.64,"speaker_id":1,"start_time":12.24,"speaker_name":"Taylor Doerbaum"},{"text":"Doing good.","index":7,"end_time":13.56,"speaker_id":1,"start_time":12.88,"speaker_name":"Taylor Doerbaum"},{"text":"It''s been a crazy allergy season here, so other than that, good.","index":8,"end_time":17.36,"speaker_id":1,"start_time":13.56,"speaker_name":"Taylor Doerbaum"},{"text":"Yeah, that''s.","index":9,"end_time":19.48,"speaker_id":0,"start_time":18.56,"speaker_name":"Nigel Sapp"},{"text":"That''s all atypical, for sure.","index":10,"end_time":21.52,"speaker_id":0,"start_time":19.48,"speaker_name":"Nigel Sapp"},{"text":"Yes.","index":11,"end_time":22.4,"speaker_id":0,"start_time":21.92,"speaker_name":"Nigel Sapp"},{"text":"Well, good.","index":12,"end_time":22.92,"speaker_id":0,"start_time":22.48,"speaker_name":"Nigel Sapp"},{"text":"I''m glad to hear.","index":13,"end_time":23.52,"speaker_id":0,"start_time":22.92,"speaker_name":"Nigel Sapp"},{"text":"Yeah, we were out of office, or not out of office, but we were at an off site, our marketing team last week, so that''s why we didn''t meet.","index":14,"end_time":30.12,"speaker_id":0,"start_time":23.52,"speaker_name":"Nigel Sapp"},{"text":"But.","index":15,"end_time":30.48,"speaker_id":0,"start_time":30.12,"speaker_name":"Nigel Sapp"},{"text":"But, yeah, everything went well.","index":16,"end_time":33.68,"speaker_id":0,"start_time":31.68,"speaker_name":"Nigel Sapp"},{"text":"So glad to be back in kind of more routines and stuff like that.","index":17,"end_time":37.68,"speaker_id":0,"start_time":33.68,"speaker_name":"Nigel Sapp"},{"text":"Yeah.","index":18,"end_time":38.28,"speaker_id":1,"start_time":37.92,"speaker_name":"Taylor Doerbaum"},{"text":"Did you guys go somewhere fun, or was it kind of in the same area?","index":19,"end_time":41.6,"speaker_id":1,"start_time":38.28,"speaker_name":"Taylor Doerbaum"},{"text":"We did.","index":20,"end_time":43.6,"speaker_id":0,"start_time":43.04,"speaker_name":"Nigel Sapp"},{"text":"We went.","index":21,"end_time":44.56,"speaker_id":0,"start_time":43.92,"speaker_name":"Nigel Sapp"},{"text":"We went up to this region that''s, like, north of San Francisco called, like, Russian river area.","index":22,"end_time":49.76,"speaker_id":0,"start_time":44.72,"speaker_name":"Nigel Sapp"},{"text":"And so we were in this Airbnb that was really nice and.","index":23,"end_time":54.43,"speaker_id":0,"start_time":50.16,"speaker_name":"Nigel Sapp"},{"text":"Or, like, it was fine, and then it was kind of in a nice area, and then we went on, like, a hike through some redwood trees, and that was really beautiful.","index":24,"end_time":61.23,"speaker_id":0,"start_time":54.43,"speaker_name":"Nigel Sapp"},{"text":"So all in all, it was.","index":25,"end_time":63.03,"speaker_id":0,"start_time":61.23,"speaker_name":"Nigel Sapp"},{"text":"Yeah, it was a really, really cool place.","index":26,"end_time":64.63,"speaker_id":0,"start_time":63.03,"speaker_name":"Nigel Sapp"},{"text":"That''s awesome.","index":27,"end_time":66.87,"speaker_id":1,"start_time":65.99,"speaker_name":"Taylor Doerbaum"},{"text":"That sounds so fun.","index":28,"end_time":67.99,"speaker_id":1,"start_time":66.95,"speaker_name":"Taylor Doerbaum"},{"text":"Yeah.","index":29,"end_time":68.63,"speaker_id":0,"start_time":68.07,"speaker_name":"Nigel Sapp"},{"text":"Thank you.","index":30,"end_time":69.67,"speaker_id":0,"start_time":69.029,"speaker_name":"Nigel Sapp"},{"text":"But anyway, so that''s us or that''s me.","index":31,"end_time":72.71,"speaker_id":0,"start_time":70.39,"speaker_name":"Nigel Sapp"},{"text":"Yeah.","index":32,"end_time":73.11,"speaker_id":0,"start_time":72.71,"speaker_name":"Nigel Sapp"},{"text":"Yeah.","index":33,"end_time":74.07,"speaker_id":1,"start_time":73.51,"speaker_name":"Taylor Doerbaum"},{"text":"Nice to get something going kind of in the beginning of the year, like that.","index":34,"end_time":77.35,"speaker_id":1,"start_time":74.39,"speaker_name":"Taylor Doerbaum"},{"text":"Get everybody ready for the rest of the year.","index":35,"end_time":79.63,"speaker_id":1,"start_time":77.75,"speaker_name":"Taylor Doerbaum"},{"text":"I feel like it''s a slow start in January.","index":36,"end_time":81.27,"speaker_id":1,"start_time":79.63,"speaker_name":"Taylor Doerbaum"},{"text":"Totally, totally.","index":37,"end_time":84.15,"speaker_id":0,"start_time":82.95,"speaker_name":"Nigel Sapp"},{"text":"Whoa.","index":38,"end_time":84.71,"speaker_id":0,"start_time":84.15,"speaker_name":"Nigel Sapp"},{"text":"Look at this.","index":39,"end_time":85.43,"speaker_id":0,"start_time":84.71,"speaker_name":"Nigel Sapp"},{"text":"Look at this.","index":40,"end_time":86.47,"speaker_id":1,"start_time":85.59,"speaker_name":"Taylor Doerbaum"},{"text":"So I know we hadn''t gone over stats in a couple weeks, so I just wanted to pull these up from the last time we met.","index":41,"end_time":91.83,"speaker_id":1,"start_time":86.63,"speaker_name":"Taylor Doerbaum"},{"text":"So, yeah, I just wanted to show this to you.","index":42,"end_time":95.07,"speaker_id":1,"start_time":93.59,"speaker_name":"Taylor Doerbaum"},{"text":"I can send this to you over a meeting, too, if you want to share with our team.","index":43,"end_time":97.39,"speaker_id":1,"start_time":95.07,"speaker_name":"Taylor Doerbaum"},{"text":"But this most recent one got a big uptick, too, which was cool to see.","index":44,"end_time":101.27,"speaker_id":1,"start_time":97.39,"speaker_name":"Taylor Doerbaum"},{"text":"So.","index":45,"end_time":102.31,"speaker_id":1,"start_time":102.07,"speaker_name":"Taylor Doerbaum"},{"text":"Yeah, I just wanted to give you an update here with the season one that we had.","index":46,"end_time":105.75,"speaker_id":1,"start_time":102.31,"speaker_name":"Taylor Doerbaum"},{"text":"Thank you.","index":47,"end_time":107.27,"speaker_id":0,"start_time":106.71,"speaker_name":"Nigel Sapp"},{"text":"Yeah.","index":48,"end_time":107.79,"speaker_id":0,"start_time":107.43,"speaker_name":"Nigel Sapp"},{"text":"Very.","index":49,"end_time":107.99,"speaker_id":1,"start_time":107.79,"speaker_name":"Taylor Doerbaum"},{"text":"No, Very, very cool.","index":50,"end_time":109.15,"speaker_id":0,"start_time":107.99,"speaker_name":"Nigel Sapp"},{"text":"Very, very cool to see.","index":51,"end_time":110.31,"speaker_id":0,"start_time":109.15,"speaker_name":"Nigel Sapp"},{"text":"Always interesting.","index":52,"end_time":112.96,"speaker_id":0,"start_time":112.08,"speaker_name":"Nigel Sapp"},{"text":"Yep.","index":53,"end_time":114.32,"speaker_id":1,"start_time":113.76,"speaker_name":"Taylor Doerbaum"},{"text":"This one always gets some new ones, which is cool.","index":54,"end_time":117.04,"speaker_id":1,"start_time":114.64,"speaker_name":"Taylor Doerbaum"},{"text":"Yeah, I think the first and the last getting the most makes sense, actually.","index":55,"end_time":123.04,"speaker_id":0,"start_time":118.32,"speaker_name":"Nigel Sapp"},{"text":"No, sorry.","index":56,"end_time":123.8,"speaker_id":0,"start_time":123.04,"speaker_name":"Nigel Sapp"},{"text":"Number nine got quite a bit as well.","index":57,"end_time":125.92,"speaker_id":0,"start_time":123.8,"speaker_name":"Nigel Sapp"},{"text":"Yeah.","index":58,"end_time":127.2,"speaker_id":1,"start_time":126.72,"speaker_name":"Taylor Doerbaum"},{"text":"Yeah.","index":59,"end_time":128.12,"speaker_id":0,"start_time":127.68,"speaker_name":"Nigel Sapp"},{"text":"Very, very interesting.","index":60,"end_time":129.12,"speaker_id":0,"start_time":128.12,"speaker_name":"Nigel Sapp"},{"text":"Very cool, though.","index":61,"end_time":130,"speaker_id":0,"start_time":129.2,"speaker_name":"Nigel Sapp"},{"text":"Yes.","index":62,"end_time":130.8,"speaker_id":1,"start_time":130.32,"speaker_name":"Taylor Doerbaum"},{"text":"So I know we talked about having that stay season one, and then anything else new we publish will go into a season two, so I can set that up on buzzsprout whenever we publish.","index":63,"end_time":141.4,"speaker_id":1,"start_time":132.32,"speaker_name":"Taylor Doerbaum"},{"text":"So I just was curious if you had any updates on if there was anything you wanted us to publish soon or new episodes coming in.","index":64,"end_time":148.52,"speaker_id":1,"start_time":141.4,"speaker_name":"Taylor Doerbaum"},{"text":"I know we have a little bit of a backlog of ones that were completed or if there''s any edits.","index":65,"end_time":152.32,"speaker_id":1,"start_time":148.52,"speaker_name":"Taylor Doerbaum"},{"text":"That''s my only outstanding things for you today.","index":66,"end_time":155.12,"speaker_id":1,"start_time":152.32,"speaker_name":"Taylor Doerbaum"},{"text":"Just to add.","index":67,"end_time":156.08,"speaker_id":1,"start_time":155.44,"speaker_name":"Taylor Doerbaum"},{"text":"Yeah.","index":68,"end_time":156.48,"speaker_id":0,"start_time":156.08,"speaker_name":"Nigel Sapp"},{"text":"Yes, I do have one episode to.","index":69,"end_time":161.68,"speaker_id":0,"start_time":158.48,"speaker_name":"Nigel Sapp"},{"text":"To send over, and then I have a few episodes that we still need to review.","index":70,"end_time":165.44,"speaker_id":0,"start_time":161.68,"speaker_name":"Nigel Sapp"},{"text":"I have a new intern, so I''m tasking her with, like, listening to those episodes.","index":71,"end_time":171.06,"speaker_id":0,"start_time":165.86,"speaker_name":"Nigel Sapp"},{"text":"So no, I today I don''t.","index":72,"end_time":173.5,"speaker_id":0,"start_time":171.14,"speaker_name":"Nigel Sapp"},{"text":"But I think through this week, we''ll make sure to get the rest out to you or out to you guys at least.","index":73,"end_time":179.22,"speaker_id":0,"start_time":173.5,"speaker_name":"Nigel Sapp"},{"text":"Yeah, that sounds great.","index":74,"end_time":180.86,"speaker_id":1,"start_time":179.7,"speaker_name":"Taylor Doerbaum"},{"text":"Yeah, we''ll keep an eye out for whenever you guys are ready.","index":75,"end_time":183.94,"speaker_id":1,"start_time":180.86,"speaker_name":"Taylor Doerbaum"},{"text":"And I did want to update you and just let you know that now that we''re only going to meet bimonthly or bi weekly.","index":76,"end_time":188.78,"speaker_id":1,"start_time":183.94,"speaker_name":"Taylor Doerbaum"},{"text":"Sorry, bi weekly?","index":77,"end_time":189.74,"speaker_id":1,"start_time":188.78,"speaker_name":"Taylor Doerbaum"},{"text":"Yeah, I did decrease the amount of points a month because we usually do 10, so it''s only going to charge five now.","index":78,"end_time":194.98,"speaker_id":1,"start_time":189.74,"speaker_name":"Taylor Doerbaum"},{"text":"So if we''re not going to meet every week.","index":79,"end_time":197.46,"speaker_id":1,"start_time":195.3,"speaker_name":"Taylor Doerbaum"},{"text":"So if there''s anything else that you guys have come up similar to like the accounting board or things like that, you''ll have those extra points now.","index":80,"end_time":204.26,"speaker_id":1,"start_time":197.82,"speaker_name":"Taylor Doerbaum"},{"text":"So if there''s any project or designer things you guys need, we''d be happy to help out with that now that we have some wiggle room there.","index":81,"end_time":211.34,"speaker_id":1,"start_time":204.26,"speaker_name":"Taylor Doerbaum"},{"text":"So especially if you don''t have new episodes too, we''ll have those extra points.","index":82,"end_time":215.26,"speaker_id":1,"start_time":211.34,"speaker_name":"Taylor Doerbaum"},{"text":"So.","index":83,"end_time":216.3,"speaker_id":1,"start_time":215.9,"speaker_name":"Taylor Doerbaum"},{"text":"Yeah, just want to let you know, keep it in mind in case there''s any to work on.","index":84,"end_time":221.02,"speaker_id":1,"start_time":216.46,"speaker_name":"Taylor Doerbaum"},{"text":"We''d love to help out.","index":85,"end_time":222.14,"speaker_id":1,"start_time":221.02,"speaker_name":"Taylor Doerbaum"},{"text":"Yeah, thank you.","index":86,"end_time":223.5,"speaker_id":0,"start_time":222.62,"speaker_name":"Nigel Sapp"},{"text":"I appreciate that.","index":87,"end_time":224.38,"speaker_id":0,"start_time":223.5,"speaker_name":"Nigel Sapp"},{"text":"Yeah, it''s just been a lot of time on strategy and figuring out how we want to structure the rest of the year, so.","index":88,"end_time":229.99,"speaker_id":0,"start_time":224.79,"speaker_name":"Nigel Sapp"},{"text":"Haven''t been as focused on podcasting and things like that, but yeah, I. I appreciate your help.","index":89,"end_time":235.99,"speaker_id":0,"start_time":230.47,"speaker_name":"Nigel Sapp"},{"text":"Yeah, of course.","index":90,"end_time":236.87,"speaker_id":1,"start_time":236.15,"speaker_name":"Taylor Doerbaum"},{"text":"No worries.","index":91,"end_time":237.35,"speaker_id":1,"start_time":236.87,"speaker_name":"Taylor Doerbaum"},{"text":"I''ll go ahead and send those stats over to you and I''ll look for any messages on updates.","index":92,"end_time":241.11,"speaker_id":1,"start_time":237.35,"speaker_name":"Taylor Doerbaum"},{"text":"But I hope you have a good rest of your week.","index":93,"end_time":242.63,"speaker_id":1,"start_time":241.11,"speaker_name":"Taylor Doerbaum"},{"text":"Yeah, you too, Taylor.","index":94,"end_time":244.39,"speaker_id":0,"start_time":243.19,"speaker_name":"Nigel Sapp"},{"text":"Bye.","index":95,"end_time":245.03,"speaker_id":1,"start_time":244.47,"speaker_name":"Taylor Doerbaum"},{"text":"All right, take care.","index":96,"end_time":246.31,"speaker_id":0,"start_time":245.43,"speaker_name":"Nigel Sapp"}],"dateString":"2026-01-20T18:03:26.000Z","host_email":null,"meeting_link":"https://us02web.zoom.us/j/87308650037?pwd=bM6sbrwhFcAqarZfIvkukcaiz8joek.1","participants":["taylor.doerbaum@marketersindemand.com"],"transcript_url":"https://app.fireflies.ai/view/01KFE96T3DRQ4REKSQX8XX1JYW","organizer_email":"taylor.doerbaum@marketersindemand.com"}'::jsonb,
